def get_cert_id(learner_id: str, level: str) -> str:
    """Generate a deterministic certificate ID."""
    import hashlib
    raw = f"{learner_id}:{level}:teamsamikoko"
    return "TGA-" + hashlib.sha256(raw.encode()).hexdigest()[:12].upper()
